+    pub fn keyLen(self: CipherSuite) usize {
+        return switch (self) {
+            .TLS_AES_128_GCM_SHA256 => 16,
+            .TLS_AES_256_GCM_SHA384 => 32,
+            .TLS_CHACHA20_POLY1305_SHA256 => 32,
+            _ => 0,
+        };
+    }
+
+    pub fn ivLen(_: CipherSuite) usize {
+        return 12; // All TLS 1.3 suites use 12-byte IV
+    }
+};
