+            0x08, 0x05, // rsa_pss_rsae_sha384
+            0x08, 0x06, // rsa_pss_rsae_sha512
+            0x04, 0x01, // rsa_pkcs1_sha256
+            0x05, 0x01, // rsa_pkcs1_sha384
+            0x06, 0x01, // rsa_pkcs1_sha512
+        };
+        @memcpy(msg[pos .. pos + sig_algs.len], &sig_algs);
+        pos += sig_algs.len;
+
+        // supported_groups (REQUIRED for key_share)
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x0a; // extension type
+        pos += 2;
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x04; // extension length = 4
+        pos += 2;
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x02; // list length = 2
+        pos += 2;
+        msg[pos] = 0x00;
+        msg[pos + 1] = 0x1d; // x25519
+        pos += 2;
+
+        // ALPN
+        if (alpn_protocols.len > 0) {
+            msg[pos] = 0x00;
+            msg[pos + 1] = 0x10;
+            pos += 2;
+
+            var alpn_len: usize = 0;
+            for (alpn_protocols) |proto| {
+                alpn_len += 1 + proto.len;
+            }
+
+            msg[pos] = @truncate((alpn_len + 2) >> 8);
+            msg[pos + 1] = @truncate(alpn_len + 2);
+            pos += 2;
+            msg[pos] = @truncate(alpn_len >> 8);
+            msg[pos + 1] = @truncate(alpn_len);
+            pos += 2;
+
+            for (alpn_protocols) |proto| {
+                msg[pos] = @truncate(proto.len);
+                pos += 1;
+                @memcpy(msg[pos .. pos + proto.len], proto);
+                pos += proto.len;
+            }
+        }
+
+        // Fill lengths
+        const ext_len: u16 = @intCast(pos - ext_start - 2);
+        msg[ext_start] = @truncate(ext_len >> 8);
+        msg[ext_start + 1] = @truncate(ext_len);
+
+        const hs_len: u24 = @intCast(pos - len_pos - 3);
+        msg[len_pos] = @truncate(hs_len >> 16);
+        msg[len_pos + 1] = @truncate(hs_len >> 8);
+        msg[len_pos + 2] = @truncate(hs_len);
+
+        self.transcript_hash.update(msg[0..pos]);
+        try self.sendRecord(.handshake, msg[0..pos]);
