+// ============================================================================
+// Tests
+// ============================================================================
+
+test "AES-GCM encrypt/decrypt roundtrip" {
+    const key = [_]u8{0} ** 16;
+    const nonce = [_]u8{0} ** 12;
+    const plaintext = "Hello, World!";
+    var ciphertext: [plaintext.len]u8 = undefined;
+    var tag: [16]u8 = undefined;
+    var decrypted: [plaintext.len]u8 = undefined;
+
+    const aes = AesGcm.init128(key);
+    aes.encrypt(nonce, plaintext, &[_]u8{}, &ciphertext, &tag);
+    try aes.decrypt(nonce, &ciphertext, &[_]u8{}, tag, &decrypted);
+
+    try std.testing.expectEqualStrings(plaintext, &decrypted);
+}
+
+test "RecordHeader parse/serialize roundtrip" {
+    const original = RecordHeader{
+        .content_type = .handshake,
+        .legacy_version = 0x0303,
+        .length = 1234,
+    };
+
+    var buf: [5]u8 = undefined;
+    original.serialize(&buf);
+
+    const parsed = try RecordHeader.parse(&buf);
+    try std.testing.expectEqual(original.content_type, parsed.content_type);
+    try std.testing.expectEqual(original.legacy_version, parsed.legacy_version);
+    try std.testing.expectEqual(original.length, parsed.length);
+}

